Indica cuál es la complejidad en el peor caso de la función replace:```unsigned bound( const vector<int>& v ) {
	for( unsigned i = 0; i < v.size(); i++ )
		if( v[i] == '0')
			return i;
	return v.size();
}

void replace( vector<int>& v, int c ) {
	for( unsigned i = 0; i < bound(v); i++)
		v[i] = c;
}
